const express = require('express');
const app = express();
const port = 3000;

// Middleware to sanitize input
const sanitizeInput = (input) => {
  if (typeof input !== 'string') {
    return '';
  }
  // Remove or escape potentially dangerous characters
  return input
    .replace(/[^\w\s\-\.\/\(\)\[\]\{\}]/g, '')
    .trim();
};

// Middleware to log user activity
const logUserActivity = (req, res, next) => {
  const action = req.query.action;
  
  if (action) {
    const sanitizedAction = sanitizeInput(action);
    const timestamp = new Date().toISOString();
    console.log(`[${timestamp}] User action: ${sanitizedAction}`);
  }
  
  next();
};

// Route to log user activity
app.get('/log', logUserActivity, (req, res) => {
  res.json({ message: 'Activity logged successfully' });
});

app.listen(port, () => {
  console.log(`Audit trail server running at http://localhost:${port}`);
});